import React, { useEffect, useState, useRef } from 'react';
import { useParams, useLocation, Link } from 'react-router-dom';
import { Project } from '../types';
import { getVimeoEmbedUrl } from '../utils/video';

type LocationState = { project?: Project };

const VideoWrapper: React.FC<{ src?: string; title?: string; autoplay?: boolean }> = ({ src, title, autoplay = true }) => {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const playerRef = useRef<any>(null);
  const pollRef = useRef<number | null>(null);
  const lastVolumeRef = useRef<number>(1);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [duration, setDuration] = useState<number>(0);
  const [time, setTime] = useState<number>(0);
  const [muted, setMuted] = useState<boolean>(true);
  const [hasPlayer, setHasPlayer] = useState<boolean>(false);
  const [initError, setInitError] = useState<string | null>(null);

  const safePlayer = () => playerRef.current;

  useEffect(() => {
    setInitError(null);
    if (!src || !containerRef.current) {
      setInitError('Missing src or container DOM node.');
      return;
    }
    let mounted = true;

    (async () => {
      try {
        const el = containerRef.current!;
        const mod = await import('@vimeo/player');
        const Player = mod.default ?? (mod as any).Player;

        // destroy previous if any
        if (playerRef.current && typeof playerRef.current.unload === 'function') {
          try { await playerRef.current.unload(); } catch {}
        }
        // create player in a div (works with url option)
        playerRef.current = new Player(el, {
          url: src as any,
          autoplay,
          controls: false,
          playsinline: true,
          loop: true,
        });

        try {
          await playerRef.current.ready();
          if (!mounted) return;
          setHasPlayer(true);
        } catch (e: any) {
          console.error('player.ready() failed:', e);
          setInitError(`Player ready failed: ${String(e?.message || e)}`);
        }

        // safe to call API methods now
        try {
          const vol = await safePlayer().getVolume();
          lastVolumeRef.current = typeof vol === 'number' ? vol : 1;
          setMuted((lastVolumeRef.current === 0));
        } catch { lastVolumeRef.current = 1; }

        if (autoplay) {
          try { await safePlayer().setVolume(0); } catch (e) { console.warn('setVolume failed', e); }
          setMuted(true);
          try { await safePlayer().play(); } catch (e) { console.warn('autoplay blocked', e); }
        } else {
          try {
            const paused = await safePlayer().getPaused();
            setIsPlaying(!paused);
          } catch {}
        }

        safePlayer().on('play', () => { if (mounted) setIsPlaying(true); });
        safePlayer().on('pause', () => { if (mounted) setIsPlaying(false); });
        safePlayer().getDuration().then((d: number) => { if (mounted) setDuration(Math.floor(d || 0)); });
        safePlayer().on('timeupdate', (data: any) => { if (mounted) setTime(Math.floor(data.seconds || 0)); });
        safePlayer().on('ended', async () => {
          try { if (!mounted) return; await safePlayer().setCurrentTime(0); await safePlayer().play(); } catch {}
        });

        if (pollRef.current) window.clearInterval(pollRef.current);
        pollRef.current = window.setInterval(async () => {
          if (!mounted || !safePlayer()) return;
          try {
            const t = await safePlayer().getCurrentTime();
            const d = await safePlayer().getDuration();
            const paused = await safePlayer().getPaused();
            if (mounted) {
              setTime(Math.floor(t || 0));
              setDuration(Math.floor(d || 0));
              setIsPlaying(!paused);
              try {
                const v = await safePlayer().getVolume();
                setMuted((typeof v === 'number' && v === 0));
              } catch {}
            }
          } catch {}
        }, 500);
      } catch (err: any) {
        console.warn('Vimeo player init failed; falling back to iframe', err);
        // fallback: inject iframe into container
        try {
          if (containerRef.current) {
            const sep = src.includes('?') ? '&' : '?';
            containerRef.current.innerHTML = `<iframe src="${src}${sep}autoplay=${autoplay ? '1' : '0'}&muted=1&playsinline=1&controls=0&loop=1" frameborder="0" allow="autoplay; fullscreen; picture-in-picture" allowfullscreen style="position:absolute;top:0;left:0;width:100%;height:100%"></iframe>`;
            setMuted(true);
          }
        } catch (e) { console.error('fallback iframe injection failed', e); }
        setInitError(`Player init error: ${String(err?.message || err)}`);
      }
    })();

    return () => {
      mounted = false;
      if (pollRef.current) window.clearInterval(pollRef.current);
      if (playerRef.current && typeof playerRef.current.unload === 'function') playerRef.current.unload().catch(()=>{});
      playerRef.current = null;
      pollRef.current = null;
      // clear fallback iframe if inserted
      if (containerRef.current) containerRef.current.innerHTML = '';
    };
  }, [src, autoplay]);

  const togglePlay = async () => {
    const p = safePlayer();
    if (!p) return;
    try {
      await p.ready();
      const paused = await p.getPaused();
      if (paused) await p.play();
      else await p.pause();
    } catch (e) { console.error('togglePlay error', e); }
  };

  const toggleMute = async () => {
    const p = safePlayer();
    if (!p) return;
    try {
      await p.ready();
      const curVol = await p.getVolume();
      lastVolumeRef.current = (typeof curVol === 'number' && curVol > 0) ? curVol : lastVolumeRef.current || 1;
      if (muted) {
        await p.setVolume(lastVolumeRef.current || 1);
        setMuted(false);
      } else {
        await p.setVolume(0);
        setMuted(true);
      }
    } catch (e) {
      console.error('toggleMute error', e);
    }
  };

  const handleFullscreen = async () => {
    // find iframe inside container (player creates one)
    const iframe = containerRef.current?.querySelector('iframe') as HTMLIFrameElement | null;
    const el = iframe || containerRef.current;
    if (!el) return;
    try {
      if ((el as any).requestFullscreen) { await (el as any).requestFullscreen(); return; }
      const anyEl: any = el;
      if (anyEl.webkitRequestFullscreen) anyEl.webkitRequestFullscreen();
    } catch (e) { console.error('fullscreen failed', e); }
  };

  const seek = async (ev: React.ChangeEvent<HTMLInputElement>) => {
    const p = safePlayer();
    if (!p) return;
    try {
      await p.ready();
      const pct = Number(ev.target.value);
      const t = (pct / 100) * (duration || 0);
      await p.setCurrentTime(t);
    } catch (e) { console.error('seek failed', e); }
  };

  return (
    <div style={{ width: '80%', maxWidth: 1200, margin: '0 auto 1.25rem' }}>
      <div style={{ marginBottom: 8, color: initError ? '#ffd' : '#8f8f8f', background: initError ? '#3b2b2b' : 'transparent', padding: initError ? '8px' : 0, borderRadius: 4 }}>
        <div style={{ fontSize: 12, color: initError ? '#ffd' : '#8f8f8f' }}>Embed URL: <code style={{ color: '#fff' }}>{src}</code></div>
        {initError && <div style={{ marginTop: 6, fontSize: 13 }}>Player error: {initError}. Check console/network & Vimeo privacy (secret hash ?h= or embed settings).</div>}
      </div>

      <div style={{ position: 'relative', paddingTop: '56.25%', background: '#111', overflow: 'hidden' }}>
        <div ref={containerRef} style={{ position: 'absolute', inset: 0 }} />
      </div>

      <div style={{ display:'flex', alignItems:'center', gap:12, marginTop:10 }}>
        <button onClick={togglePlay} style={{ background: 'transparent', border: '1px solid rgba(255,255,255,0.12)', color: '#EDEDED', padding: '6px 10px', cursor: 'pointer', fontFamily: 'IBM Plex Mono, monospace', textTransform: 'uppercase', fontSize: 12, letterSpacing: '0.12em' }}>
          {isPlaying ? 'Pause' : 'Play'}
        </button>

        <button onClick={toggleMute} style={{ background: 'transparent', border: '1px solid rgba(255,255,255,0.12)', color: '#EDEDED', padding: '6px 10px', cursor: hasPlayer ? 'pointer' : 'not-allowed', fontFamily: 'IBM Plex Mono, monospace', textTransform: 'uppercase', fontSize: 12, letterSpacing: '0.12em', opacity: hasPlayer ? 1 : 0.6 }}>
          {muted ? 'Unmute' : 'Mute'}
        </button>

        <button onClick={handleFullscreen} style={{ background: 'transparent', border: '1px solid rgba(255,255,255,0.12)', color: '#EDEDED', padding: '6px 10px', cursor: 'pointer', fontFamily: 'IBM Plex Mono, monospace', textTransform: 'uppercase', fontSize: 12, letterSpacing: '0.12em' }}>
          Fullscreen
        </button>

        <input type="range" min={0} max={100} value={duration ? Math.min(100, Math.round((time/duration)*100)) : 0} onChange={seek} style={{ flex:1 }} />

        <div style={{ color:'#bdbdbd' }}>{duration ? `${time}/${duration}s` : '--/--'}</div>
      </div>
    </div>
  );
};

const ProjectDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation<LocationState>();
  const [project, setProject] = useState<Project | null>(location.state?.project ?? null);
  const [loading, setLoading] = useState<boolean>(!project);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (project) return;
    let mounted = true;
    setLoading(true);

    (async () => {
      try {
        const res = await fetch(`/api/projects/${id}`);
        if (!res.ok) throw new Error('Network response was not ok');
        const raw = await res.json();
        const normalized: Project = {
          ...raw,
          createdAt: raw.createdAt ? new Date(raw.createdAt) : raw.createdAt,
          updatedAt: raw.updatedAt ? new Date(raw.updatedAt) : raw.updatedAt,
          videoUrl: raw.videoUrl ?? raw.originalVideoLink ?? raw.link ?? raw.videoUrl,
          link: raw.link ?? raw.videoUrl ?? raw.originalVideoLink ?? raw.link,
        };
        if (mounted) setProject(normalized);
      } catch (err) {
        if (mounted) setError('Failed to load project.');
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => { mounted = false; };
  }, [id, project]);

  if (loading) return <div style={{ padding: 40 }}>Loading…</div>;
  if (error) return <div style={{ padding: 40 }}>{error}</div>;
  if (!project) return <div style={{ padding: 40 }}>Project not found.</div>;

  const videoSrcRaw = (project as any).videoUrl || (project as any).originalVideoLink || (project as any).link || '';
  const videoSrc = getVimeoEmbedUrl(videoSrcRaw);

  // debug + heuristic for missing secret hash (private Vimeo)
  // show a small warning when embed might be blocked
  const embedLikelyBlocked = !!videoSrc && videoSrc.includes('player.vimeo.com') && !videoSrc.includes('?h=');

  // log for debugging (remove after debugging)
  // eslint-disable-next-line no-console
  console.debug('ProjectDetail: project raw', project);
  // eslint-disable-next-line no-console
  console.debug('ProjectDetail: videoSrcRaw ->', videoSrcRaw);
  // eslint-disable-next-line no-console
  console.debug('ProjectDetail: computed embed URL ->', videoSrc);

  return (
    <main style={{ padding: '3rem 4rem', textAlign: 'center' }}>
      <Link to="/" style={{ display: 'inline-block', marginBottom: '1rem', color: '#EDEDED', textDecoration: 'none' }}>
        ← Back
      </Link>

      {embedLikelyBlocked && (
        <div style={{ background: '#2b2b2b', color: '#ffd', padding: '10px 12px', borderRadius: 4, marginBottom: 12, maxWidth: 720, margin: '0 auto 1rem' }}>
          Warning: this Vimeo may be private or missing a secret hash. Embedding might be blocked. Try opening the raw link:
          {' '}
          <a href={videoSrcRaw || '#'} target="_blank" rel="noreferrer" style={{ color: '#fff', textDecoration: 'underline', marginLeft: 6 }}>
            Open video
          </a>
          {' '}or ensure the project saved the full embed URL (with ?h=HASH) and Vimeo allows embedding on this domain.
        </div>
      )}

      <VideoWrapper src={videoSrc || (project.thumbnail ?? '')} title={project.title} autoplay />

      <div style={{ maxWidth: 900, margin: '0 auto', textAlign: 'center', color: '#ddd' }}>
        {project.description ? <p style={{ marginTop: 12, lineHeight: 1.6 }}>{project.description}</p> : null}
      </div>

      <section style={{ marginTop: 28 }}>

        <h1 style={{ fontFamily: 'Playfair Display, serif', color: '#EDEDED', margin: '0 0 1rem 0' }}>
        {project.title}
      </h1>

      <div style={{ color: '#bdbdbd', textTransform: 'uppercase', letterSpacing: '0.12em', fontSize: '0.85rem', marginBottom: '1.5rem' }}>
        {project.category ?? 'All Projects'}{project.role ? ` — ${project.role}` : ''}
      </div>

        <h3 style={{ fontSize: '0.85rem', textTransform: 'uppercase', letterSpacing: '0.12em', color: '#bdbdbd', marginBottom: '0.75rem' }}>
          Additional Material
        </h3>

        {Array.isArray((project as any).assets) && (project as any).assets.length > 0 ? (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '0.75rem' }}>
            {(project as any).assets.map((a: any, i: number) => (
              <div key={i} style={{ background: '#111', padding: 8 }}>
                {a.type === 'video' ? (
                  <iframe
                    src={getVimeoEmbedUrl(a.src)}
                    title={`asset-${i}`}
                    frameBorder="0"
                    allow="autoplay; fullscreen; picture-in-picture"
                    allowFullScreen
                    style={{ width: '100%', height: 120 }}
                  />
                ) : (
                  <img src={a.src} alt={a.label || `asset-${i}`} style={{ width: '100%', height: 120, objectFit: 'cover' }} />
                )}
              </div>
            ))}
          </div>
        ) : (
          <div style={{ color: '#8f8f8f' }}>No extra assets. Add photos / bts / other videos in the admin panel.</div>
        )}
      </section>
    </main>
  );
};

export default ProjectDetail;
